using System;

class Program
{
    static void Main()
    {
        int count = 1;
        int sum = 0;

        while (count <= 10)
        {
            sum += count;
            Console.WriteLine($"Adding {count}, sum = {sum}");
            count++;
        }

        Console.WriteLine($"\nTotal sum: {sum}");
    }
}
